export const advanceGenerations = (aliveCells: Array<[number, number]>, steps: number): Array<[number, number]> => {
  if (steps === 0) {
    return aliveCells;
  }
  // TODO: Implement generation advancement for steps > 0
  throw new Error("Not yet implemented");
};

