const countLiveNeighbors = (x: number, y: number, aliveCells: Set<string>): number => {
  let count = 0;
  for (let dx = -1; dx <= 1; dx++) {
    for (let dy = -1; dy <= 1; dy++) {
      if (dx === 0 && dy === 0) continue;
      const key = `${x + dx},${y + dy}`;
      if (aliveCells.has(key)) count++;
    }
  }
  return count;
};

const advanceOneGeneration = (aliveCells: Array<[number, number]>): Array<[number, number]> => {
  const aliveSet = new Set(aliveCells.map(([x, y]) => `${x},${y}`));
  const cellsToCheck = new Set<string>();

  // Add all alive cells and their neighbors to check
  aliveCells.forEach(([x, y]) => {
    cellsToCheck.add(`${x},${y}`);
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        cellsToCheck.add(`${x + dx},${y + dy}`);
      }
    }
  });

  const nextGen: Array<[number, number]> = [];
  cellsToCheck.forEach((key) => {
    const [x, y] = key.split(",").map(Number) as [number, number];
    const liveNeighbors = countLiveNeighbors(x, y, aliveSet);
    const isAlive = aliveSet.has(key);

    // Survival: live cell with 2 or 3 neighbors lives
    if (isAlive && (liveNeighbors === 2 || liveNeighbors === 3)) {
      nextGen.push([x, y]);
    }
    // Reproduction: dead cell with exactly 3 neighbors becomes alive
    else if (!isAlive && liveNeighbors === 3) {
      nextGen.push([x, y]);
    }
  });

  return nextGen.sort(([ax, ay], [bx, by]) => ax === bx ? ay - by : ax - bx);
};

export const advanceGenerations = (aliveCells: Array<[number, number]>, steps: number): Array<[number, number]> => {
  if (steps === 0) {
    return aliveCells;
  }

  let current = aliveCells;
  for (let i = 0; i < steps; i++) {
    current = advanceOneGeneration(current);
  }
  return current;
};

